#include "stm32h5xx_ll_bus.h"
#include "stm32h5xx_ll_gpio.h"
#include "stm32h5xx_ll_utils.h"
#include "DDR5_Board.h"

volatile uint32_t g_ms_ticks = 0;

void SysTick_Handler(void)
{
    g_ms_ticks++;
}

static inline void delay_ms(uint32_t ms)
{
    uint32_t start = g_ms_ticks;
    while ((g_ms_ticks - start) < ms)
    {
    }
}

int main(void)
{
    uint8_t cmd_clear[] = {0xFE, 0x51};
    uint8_t txt_hola[]  = {'H', 'O', 'L', 'A'};
    int rc;

    DDR5_Clock_Init();
    DDR5_GPIO_Init();
    DDR5_UART_Init_115200_8N1(USART3, 64000000U);
    DDR5_I2C1_Init();

    DDR5_UART_WriteString(USART3, "DDR5_TEST_PLATFORM\r\n", 100000U);

    /* Espera tras power-up del LCD */
    delay_ms(200);

    /* Ping real con 1 byte */
    rc = DDR5_I2C_Ping(I2C1, 0x28U);
    if (rc == 0)
    {
        DDR5_UART_WriteString(USART3, "I2C ACK 0x28\r\n", 100000U);
    }
    else
    {
        DDR5_UART_WriteString(USART3, "I2C NO ACK 0x28\r\n", 100000U);
        while (1)
        {
        }
    }

    /* Clear display */
    rc = DDR5_I2C_WriteRaw(I2C1, 0x28U, cmd_clear, sizeof(cmd_clear));
    if (rc == 0)
    {
        DDR5_UART_WriteString(USART3, "LCD CLEAR OK\r\n", 100000U);
    }
    else
    {
        DDR5_UART_WriteString(USART3, "LCD CLEAR FAIL\r\n", 100000U);
    }

    delay_ms(5);

    /* Write HOLA */
    rc = DDR5_I2C_WriteRaw(I2C1, 0x28U, txt_hola, sizeof(txt_hola));
    if (rc == 0)
    {
        DDR5_UART_WriteString(USART3, "LCD WRITE OK\r\n", 100000U);
    }
    else
    {
        DDR5_UART_WriteString(USART3, "LCD WRITE FAIL\r\n", 100000U);
    }

    while (1)
    {
        LED_STOP_ON();
        delay_ms(500);
        LED_STOP_OFF();
        delay_ms(500);
    }
}
